fn method(
    methods: &mut BTreeMap<String, MethodSchemaBinding>,
    method: impl Into<String>,
    binding: MethodSchemaBinding,
) {
    methods.insert(method.into(), binding);
}

fn devo_method<P: JsonSchema, R: JsonSchema>(
    methods: &mut BTreeMap<String, MethodSchemaBinding>,
    client_method: ClientMethod,
) {
    let params = Box::leak(P::schema_name().into_boxed_str());
    let result = Box::leak(R::schema_name().into_boxed_str());
    devo_method_named(methods, client_method, params, result);
}

fn devo_request_only<P: JsonSchema>(
    methods: &mut BTreeMap<String, MethodSchemaBinding>,
    client_method: ClientMethod,
) {
    devo_method_binding(
        methods,
        client_method,
        MethodSchemaBinding {
            outgoing_request: Some(Box::leak(P::schema_name().into_boxed_str())),
            ..MethodSchemaBinding::default()
        },
    );
}

fn devo_notification<P: JsonSchema>(
    methods: &mut BTreeMap<String, MethodSchemaBinding>,
    method_name: &'static str,
) {
    let binding = MethodSchemaBinding {
        incoming_notification: Some(Box::leak(P::schema_name().into_boxed_str())),
        ..MethodSchemaBinding::default()
    };
    methods
        .entry(method_name.to_string())
        .or_insert_with(|| binding.clone());
    methods.insert(devo_extension_method(method_name), binding);
}

fn devo_method_named(
    methods: &mut BTreeMap<String, MethodSchemaBinding>,
    client_method: ClientMethod,
    params: &'static str,
    result: &'static str,
) {
    devo_method_binding(
        methods,
        client_method,
        MethodSchemaBinding {
            outgoing_request: Some(params),
            incoming_result: Some(result),
            ..MethodSchemaBinding::default()
        },
    );
}

fn devo_method_binding(
    methods: &mut BTreeMap<String, MethodSchemaBinding>,
    client_method: ClientMethod,
    binding: MethodSchemaBinding,
) {
    let method_name = client_method.as_str();
    methods
        .entry(method_name.to_string())
        .or_insert_with(|| binding.clone());
    methods.insert(devo_extension_method(method_name), binding);
}

fn schema<T: JsonSchema>(schemas: &mut BTreeMap<String, RootSchema>) {
    schema_named::<T>(&T::schema_name(), schemas);
}

fn schema_named<T: JsonSchema>(name: &str, schemas: &mut BTreeMap<String, RootSchema>) {
    let mut schema = schemars::schema_for!(T);
    schema.schema.metadata().title = Some(name.to_string());
    schemas.insert(name.to_string(), schema);
}
